using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

var builder = Host.CreateApplicationBuilder(args);

// CRITICAL: stdio transport uses stdout for JSON-RPC — all logging must go to stderr.
builder.Logging.AddConsole(options =>
    options.LogToStandardErrorThreshold = LogLevel.Trace);

// Register an HttpClient with a base address for the API tools.
// The DI container injects this into the ApiTools constructor automatically.
builder.Services.AddHttpClient<ApiMcpServer.ApiTools>(client =>
{
    client.BaseAddress = new Uri("https://jsonplaceholder.typicode.com");
});

builder.Services.AddMcpServer(options =>
{
    options.ServerInfo = new() { Name = "ApiMcpServer", Version = "1.0.0" };
    options.ServerInstructions = "Use these tools to interact with the user management API.";
})
.WithStdioServerTransport()
.WithToolsFromAssembly();

await builder.Build().RunAsync();

